  ~BFTask() {
    if (doBackup)
      performBackup();

    tape.clear();
    if (_sqlite3ErrMsg)
      sqlite3_free(_sqlite3ErrMsg);
    if (db)
      sqlite3_close(db);
  }

  void run(const std::string &program, bool deletePreviousState) {
    if (deletePreviousState) {
      tape.clear();
      loopStack.clear();
      instructionPointer = 0;
      dataPointer = 0;
    }

    while (instructionPointer < program.length()) {
      char command = program[instructionPointer];
      switch (command) {
      case '>':
        incrementDataPointer();
        break;
      case '<':
        decrementDataPointer();
        break;
      case '+':
        incrementCellValue();
        break;
      case '-':
        decrementCellValue();
        break;
      case '.':
        outputCellValue();
        break;
      case ',':
        inputCellValue();
        break;
      case '[':
        if (getCellValue() == 0) {
          size_t loopDepth = 1;
          while (loopDepth > 0) {
            if (loopDepth == LOOP_DEPTH_MAX)
              throw std::runtime_error("nested loop depth exceeded.");

            instructionPointer++;
            if (program[instructionPointer] == '[') {
              loopDepth++;
            } else if (program[instructionPointer] == ']') {
              loopDepth--;
            }
          }
        } else {
          loopStack.push_back(instructionPointer);
        }
        break;
      case ']':
        if (getCellValue() != 0) {
          instructionPointer = loopStack.back() - 1;
        } else {
          loopStack.pop_back();
        }
